// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  windSpeedUnit: string; // Wind speed unit (m/s, km/h, mph, etc.)
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; condition?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const getWeatherEmoji = useCallback((condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sun')) return '☀️';
    if (lowerCondition.includes('cloud')) return '☁️';
    if (lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('thunder') || lowerCondition.includes('storm')) return '⛈️';
    if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
    return '🌤️';
  }, []);

  return {
    getWeatherEmoji,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Main Weather Card */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24} align="center">
            {/* City and Condition */}
            <Stack gap={8} align="center">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>

            {/* Weather Icon */}
            {/* Weather Icon */}
            <div style={{ fontSize: '72px', lineHeight: 1 }} aria-label={`Weather: ${props.condition}`} role="img">
              {state.getWeatherEmoji(props.condition)}
            </div>

            {/* Temperature Display */}
            <div style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: 1.2,
            }}>
              {props.temperature}°{props.unit}
            </div>

            {/* Humidity and Wind */}
            <Stack direction="horizontal" gap={32} justify="center" align="center" wrap>
              <Stack gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
              </Stack>
              <Stack gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} {props.windSpeedUnit}</Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding={20} radius="lg">
            <Stack gap={16}>
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">5-Day Forecast</Heading>
              <Stack direction="horizontal" gap={12} justify="start" align="stretch" wrap>
                {props.forecast.map((dayForecast, index) => (
                  <Box
                    key={index}
                    padding={16}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      flex: '1 1 auto',
                      minWidth: '100px',
                      textAlign: 'center',
                    }}
                  >
                    <Stack gap={12} align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="semibold">
                        {dayForecast.day || `Day ${index + 1}`}
                      </Text>
                      <div style={{ fontSize: '32px', lineHeight: 1 }} aria-label={`Forecast: ${dayForecast.condition || dayForecast.day || `Day ${index + 1}`}`} role="img">
                        {dayForecast.icon || state.getWeatherEmoji(dayForecast.condition || 'clear')}
                      </div>
                      <Stack gap={4} align="center">
                        <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                          {dayForecast.high ?? 'N/A'}°
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {dayForecast.low ?? 'N/A'}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                ))}
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction('submit');

  // Step tracking and form state
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Email validation
  const isValidEmail = useCallback((value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Validation for current step
  const isStepValid = useCallback(() => {
    switch (currentStep) {
      case 1:
        return name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
      case 2:
        return satisfaction !== '';
      case 3:
        return true; // Features selection is optional
      case 4:
        return true; // Comments are optional, review step is always valid
      default:
        return false;
    }
  }, [currentStep, name, email, satisfaction, isValidEmail]);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (isStepValid()) {
      if (currentStep === 4) {
        // Submit the form on final step
        submit({
          name,
          email,
          satisfaction: parseInt(satisfaction, 10),
          features,
          comments,
        });
      } else {
        setCurrentStep(currentStep + 1);
      }
    }
  }, [currentStep, isStepValid, name, email, satisfaction, features, comments, submit]);

  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
  }, [currentStep]);

  // Email error message
  const emailError = email.trim() !== '' && !isValidEmail(email) ? 'Please enter a valid email address' : '';

  // Feature toggle handler
  const toggleFeature = useCallback((feature: string) => {
    setFeatures(prev => {
      if (prev.includes(feature)) {
        return prev.filter(f => f !== feature);
      } else {
        return [...prev, feature];
      }
    });
  }, []);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    toggleFeature,
    comments,
    setComments,
    isStepValid,
    handleNext,
    handleBack,
    emailError,
  };
}


export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={1}>Customer Feedback Survey</Heading>
          <Progress
            value={state.currentStep}
            max={4}
            variant="default"
            size="md"
            showLabel
          />
        </Stack>

        {/* Step 1: Name and Email */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2}>Step 1 of 4: Your Information</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={state.name}
                onChange={state.setName}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={state.email}
                onChange={state.setEmail}
                error={state.emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2}>Step 2 of 4: How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2}>Step 3 of 4: Which Features Interest You?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select all that apply (optional)
              </Text>
              <Stack gap={12}>
                {props.featureOptions.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={2}>Step 4 of 4: Additional Comments</Heading>
              <TextArea
                label="Your Feedback"
                placeholder="Tell us what you think..."
                value={state.comments}
                onChange={state.setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review — shown after final step submission is pending/complete */}

        {/* Navigation Buttons */}
        <Row gap={12} justify="between">
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          <Button
            variant="primary"
            onClick={state.handleNext}
            disabled={!state.isStepValid()}
          >
            {state.currentStep === 4 ? 'Submit' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Local state for tasks and UI
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync props to local state when they change
  React.useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle real-time updates from stream via ggui:agent-data events
  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      const evt = customEvent.detail;
      if (evt.action === 'delete' && evt.task?.id) {
        setTasks(prev => prev.filter(t => t.id !== evt.task?.id));
      } else if (evt.action === 'create' && evt.task?.id) {
        setTasks(prev => [...prev, evt.task!]);
      } else if ((evt.action === 'move' || evt.action === 'edit') && evt.task?.id) {
        setTasks(prev => prev.map(t => t.id === evt.task?.id ? { ...t, ...evt.task } : t));
      }
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  // Computed: tasks grouped by column
  const tasksByColumn = React.useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach(col => {
      grouped[col.id || ''] = tasks.filter(t => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  // Handler: move task to different column
  const moveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    window.dispatchEvent(new CustomEvent('ggui:action-taskUpdate', { detail: { action: 'move', taskId, data: { column: newColumn } } }));
  }, []);

  // Handler: start editing task title
  const startEdit = useCallback((task: typeof tasks[0]) => {
    setEditingTaskId(task.id || null);
    setEditingTitle(task.title || '');
  }, []);

  // Handler: save edited title
  // Handler: save edited title
  const saveEdit = useCallback((taskId: string) => {
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: editingTitle } : t));
    window.dispatchEvent(new CustomEvent('ggui:action-taskUpdate', { detail: { action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } } }));
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, tasks]);

  // Handler: add new task to column
  // Handler: add new task to column
  const addTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '',
      dueDate: undefined,
    };
    setTasks(prev => [...prev, newTask]);
    window.dispatchEvent(new CustomEvent('ggui:action-taskUpdate', { detail: { action: 'create', taskId: newTask.id, data: { column: columnId } } }));
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingToColumn(null);
  }, [newTaskTitle, newTaskPriority]);

  return { tasks, editingTaskId, editingTitle, setEditingTitle, startEdit, saveEdit, addingToColumn, setAddingToColumn, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, addTask, moveTask, tasksByColumn, totalTasks, completedTasks };

}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={12} padding={16}>
          <Stack direction="horizontal" align="center" justify="between">
            <div>
              <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Progress</Text>
              <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">{state.completedTasks} of {state.totalTasks} tasks completed</Heading>
            </div>
            <Progress value={(state.totalTasks > 0 ? (state.completedTasks / state.totalTasks) * 100 : 0)} variant="success" size="md" />
          </Stack>
        </Box>

        {/* Kanban Columns */}
        <Stack direction="horizontal" gap={16} align="start">
          {props.columns.map((column) => {
            const columnTasks = state.tasksByColumn[column.id || ''] || [];
            return (
              <Card key={column.id} shadow="sm" padding={16} border={true} radius="lg" style={{ flex: '1 1 300px', minWidth: '300px' }}>
                <Stack gap={16}>
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack gap={8} direction="horizontal" align="center">
                      <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{column.name}</Heading>
                      <Badge variant="default" size="sm">{columnTasks.length}</Badge>
                    </Stack>
                  </Stack>

                  {/* Task Cards */}
                  <Stack gap={12}>
                    {columnTasks.map((task) => (
                      <Card key={task.id} shadow="sm" padding={12} border={true} radius="md" background="var(--ggui-color-surface, #ffffff)">
                        <Stack gap={8}>
                          {/* Task Title */}
                          {state.editingTaskId === task.id ? (
                            <Stack gap={8} direction="horizontal">
                              <Input
                                value={state.editingTitle}
                                onChange={state.setEditingTitle}
                                placeholder="Task title"
                                size="sm"
                                style={{ flex: 1 }}
                              />
                              <Button
                                size="xs"
                                variant="primary"
                                onClick={() => state.saveEdit(task.id || '')}
                              >
                                Save
                              </Button>
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={() => {
                                  state.setEditingTaskId(null);
                                  state.setEditingTitle('');
                                }}
                              >
                                Cancel
                              </Button>
                            </Stack>
                          ) : (
                            <Stack gap={4} direction="horizontal" justify="between" align="center">
                              <Text
                                variant="body"
                                color="var(--ggui-color-onSurface, #18181b)"
                                weight="medium"
                                style={{ cursor: 'pointer', flex: 1 }}
                                as={Clickable}
                                onClick={() => state.startEdit(task)}
                              >
                                {task.title}
                              </Text>
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={() => state.startEdit(task)}
                              >
                                <Icon name="edit" size={14} />
                              </Button>
                            </Stack>
                          )}

                          {/* Priority Badge */}
                          {task.priority && (
                            <Badge
                              variant={
                                task.priority === 'high'
                                  ? 'error'
                                  : task.priority === 'medium'
                                    ? 'warning'
                                    : 'success'
                              }
                              size="sm"
                              pill={true}
                            >
                              {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                            </Badge>
                          )}

                          {/* Assignee Avatar and Due Date */}
                          <Stack direction="horizontal" gap={8} align="center" justify="between">
                            {task.assignee ? (
                              <Avatar name={task.assignee} size="sm" shape="circle" />
                            ) : (
                              <Box style={{ width: '24px', height: '24px' }} />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                              </Text>
                            )}
                          </Stack>

                          {/* Move Controls */}
                          <Dropdown
                            trigger={<Button size="xs" variant="outline">Move</Button>}
                            options={props.columns
                              .filter(col => col.id !== column.id)
                              .map(col => ({
                                value: col.id || '',
                                label: col.name || '',
                              }))}
                            value=""
                            onChange={(newColumnId) => state.moveTask(task.id || '', newColumnId)}
                            placement="bottom-start"
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Form */}
                  {state.addingToColumn === column.id ? (
                    <Card shadow="none" padding={12} border={true} radius="md" background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                      <Stack gap={8}>
                        <Input
                          label="Task Title"
                          value={state.newTaskTitle}
                          onChange={state.setNewTaskTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={state.newTaskPriority}
                          onChange={(v) => state.setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Stack direction="horizontal" gap={8}>
                          <Button
                            size="xs"
                            variant="primary"
                            onClick={() => state.addTask(column.id || '')}
                          >
                            Add
                          </Button>
                          <Button
                            size="xs"
                            variant="ghost"
                            onClick={() => {
                              state.setAddingToColumn(null);
                              state.setNewTaskTitle('');
                              state.setNewTaskPriority('medium');
                            }}
                          >
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      fullWidth
                      variant="outline"
                      size="sm"
                      onClick={() => state.setAddingToColumn(column.id || '')}
                    >
                      <Icon name="plus" size={16} /> Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

