}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search term (by name or symbol)
  const filteredElements = useMemo(() => {
    if (!searchTerm.trim()) return props.elements;
    const query = searchTerm.toLowerCase();
    return props.elements.filter(el => 
      (el.name?.toLowerCase().includes(query)) || 
      (el.symbol?.toLowerCase().includes(query))
    );
  }, [searchTerm, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats);
  }, [props.elements]);

  // Category color map using design tokens
  const categoryColors: Record<string, { bg: string; text: string }> = {
    'Alkali Metal': { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-700, #0369a1)' },
    'Alkaline Earth Metal': { bg: 'var(--ggui-color-warning-50, #fffbeb)', text: 'var(--ggui-color-warning-700, #b45309)' },
    'Transition Metal': { bg: 'var(--ggui-color-info-50, #ecfeff)', text: 'var(--ggui-color-info-700, #0e7490)' },
    'Post-Transition Metal': { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)' },
    'Nonmetal': { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-700, #15803d)' },
    'Halogen': { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-700, #b91c1c)' },
    'Noble Gas': { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-900, #0c4a6e)' },
    'Lanthanide': { bg: 'var(--ggui-color-container, #ede9fe)', text: 'var(--ggui-color-onContainer, #4c1d95)' },
    'Actinide': { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-900, #082f49)' },
  };

  const getColorForCategory = (category?: string) => {
    if (!category) return { bg: 'var(--ggui-color-outline, #d4d4d8)', text: 'var(--ggui-color-onSurface, #18181b)' };
    return categoryColors[category] || { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurface, #18181b)' };
  };

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  return {
    searchTerm,
    setSearchTerm,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getColorForCategory,
    handleElementClick,
  };
}

