}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  // Note: useAction imported from wire hooks, not available in this scope

  // State for quantity selector
  const [quantity, setQuantity] = useState(1);

  // Computed values
  const isOutOfStock = !props.product.stock || props.product.stock === 0;
  const isLowStock = props.product.stock && props.product.stock > 0 && props.product.stock <= 5;
  const formattedPrice = props.product.price ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}` : 'N/A';

  // Handler for quantity increment/decrement
  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity(prev => {
      const newQty = prev + delta;
      const maxQty = props.product.stock || 1;
      return Math.max(1, Math.min(newQty, maxQty));
    });
  }, [props.product.stock]);

  // Handler for add to cart
  const handleAddToCart = useCallback(() => {
    if (props.product.id && props.onAddToCart) {
      props.onAddToCart({ productId: props.product.id, quantity: state.quantity });
    }
  }, [props.product.id, props.onAddToCart, state.quantity]);

  return { quantity, setQuantity, isOutOfStock, isLowStock, formattedPrice, handleQuantityChange, handleAddToCart };
}

