import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  // Local state for message composition and display
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingSender, setTypingSender] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Fire-and-forget to agent
  const sendMessage = useCallback((payload: ActionSendMessagePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'sendMessage', payload } }));
  }, []);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Listen for real-time stream events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { stream, data } = customEvent.detail;

      if (stream === 'message' && data) {
        setMessages((prev) => [...prev, data]);
        scrollToBottom();
      } else if (stream === 'typing' && data) {
        setTypingSender(data.active && data.sender !== props.currentUser ? data.sender : null);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, [props.currentUser, scrollToBottom]);

  // Send message handler
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      sendMessage(payload);
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key to send message
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  return { sendMessage, messages, inputValue, setInputValue, handleSendMessage, handleKeyDown, typingSender, messagesEndRef };
}


// Inject typing animation keyframes
