          </Stack>
        </Stack>
      </Box>

      {/* Messages Container */}
      <Box paddingX={16} paddingY={12} style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-2, 8px)' }}>
        {state.messages.length === 0 ? (
          <Box style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', flex: 1 }}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No messages yet. Start the conversation!</Text>
          </Box>
        ) : (
          <>
            {state.messages.map((msg, index) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const showSenderName = index === 0 || state.messages[index - 1].sender !== msg.sender;
              const timestamp = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
              return (
