                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                      style={{ marginTop: '4px', marginBottom: 0 }}
                    >
                      {timestamp}
                    </Text>
                  </Box>
                </Stack>
              );
