        {/* Typing Indicator */}
        {state.typingSender && (
          <Stack gap={4} align="start">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.typingSender}</Text>
            <Box paddingX={12} paddingY={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
              <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" style={{ margin: 0 }}>
                <span style={{ animation: 'ggui-fade-typing 1.4s infinite' }}>·</span>
                <span style={{ animation: 'ggui-fade-typing 1.4s infinite 0.2s', marginLeft: '4px', marginRight: '4px' }}>·</span>
                <span style={{ animation: 'ggui-fade-typing 1.4s infinite 0.4s' }}>·</span>
              </Text>
            </Box>
          </Stack>
        )}

        {/* Scroll anchor */}
        <div ref={state.messagesEndRef} />
      </Box>

      {/* Input Area */}
      <Box paddingX={16} paddingY={12} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <Input
            label=""
            placeholder="Type a message..."
            value={state.inputValue}
            onChange={state.setInputValue}
            onKeyDown={state.handleKeyDown}
            size="md"
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={state.handleSendMessage}
            disabled={!state.inputValue.trim()}
            rightIcon={<Icon name="send" size={16} />}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

