// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  // State for tracking stock data and recent updates for highlight animation
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<string>(new Date().toLocaleTimeString());
  const [updatedSymbols, setUpdatedSymbols] = useState<Set<string>>(new Set());
  const [marketStatus, setMarketStatus] = useState<StreamMarketStatus | null>(null);

  // Merge price updates into stock data
  const handlePriceUpdate = useCallback(() => {
    // This callback is kept for potential future use with useStream
    // Currently, updates come through the window event listener below
  }, []);

  // Listen for real-time agent data events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data.type === 'priceUpdate') {
        const update = data.data as StreamPriceUpdate;
        setStocks((prevStocks) => {
          const updated = prevStocks.map((stock) => {
            if (stock.symbol === update.symbol) {
              return {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              };
            }
            return stock;
          });
          return updated;
        });
        setLastUpdatedTime(new Date().toLocaleTimeString());
        setUpdatedSymbols((prev) => new Set(prev).add(update.symbol || ''));
        const timer = setTimeout(() => {
          setUpdatedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol || '');
            return next;
          });
        }, 500);
      } else if (data.type === 'marketStatus') {
        setMarketStatus(data.data as StreamMarketStatus);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  return { stocks, lastUpdatedTime, updatedSymbols, marketStatus };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Determine color scheme based on price change
  const getChangeColor = (change?: number) => {
    if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    return change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
  };

  const getChangeBorderColor = (change?: number) => {
    if (change === undefined) return 'var(--ggui-color-outline, #d4d4d8)';
    return change >= 0 ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)';
  };

  const getChangeBackgroundColor = (change?: number) => {
    if (change === undefined) return 'transparent';
    return change >= 0 ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)';
  };

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Header Section */}
        <Box>
          <Stack gap={8}>
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Row align="center" gap={12}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {state.lastUpdatedTime}
              </Text>
               {state.marketStatus && (
                 <Badge variant={state.marketStatus.status === 'open' ? 'success' : 'default'} size="sm">
                   {state.marketStatus.status ? state.marketStatus.status.charAt(0).toUpperCase() + state.marketStatus.status.slice(1) : 'Market'}
                </Badge>
              )}
            </Row>
          </Stack>
        </Box>

        <Divider />

        {/* Stock Cards Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {state.stocks.map((stock) => {
            const changeColor = getChangeColor(stock.change);
            const isUpdating = state.updatedSymbols.has(stock.symbol || '');
            return (
              <Card
                key={stock.symbol}
                padding={20}
                shadow="md"
                radius="lg"
                style={{
                  borderLeft: `4px solid ${getChangeBorderColor(stock.change)}`,
                  backgroundColor: isUpdating ? getChangeBackgroundColor(stock.change) : 'var(--ggui-color-surface, #fafafa)',
                  transition: 'background-color 200ms ease-in-out',
                }}
              >
                <Stack gap={12}>
                  {/* Ticker and Company Name */}
                  <Box>
                    <Heading
                      level={3}
                      color="var(--ggui-color-onSurface, #18181b)"
                      align="left"
                    >
                      {stock.symbol}
                    </Heading>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {stock.name}
                    </Text>
                  </Box>

                  <Divider />

                  {/* Price Section */}
                  <Box>
                    <Text
                      variant="body"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${stock.price?.toFixed(2) ?? 'N/A'}
                    </Text>
                  </Box>

                  {/* Change Section */}
                  <Row align="center" gap={8}>
                    <Text
                      variant="body"
                      weight="semibold"
                      color={changeColor}
                    >
                      {stock.change && stock.change > 0 ? '+' : ''}{stock.change?.toFixed(2) ?? 'N/A'}
                    </Text>
                    <Row align="center" gap={4}>
                      <Icon
                        name={stock.change && stock.change >= 0 ? 'arrow-up' : 'arrow-down'}
                        size={16}
                        color={changeColor}
                      />
                      <Text
                        variant="body"
                        weight="semibold"
                        color={changeColor}
                      >
                        {stock.changePercent && stock.changePercent > 0 ? '+' : ''}{stock.changePercent?.toFixed(2) ?? 'N/A'}%
                      </Text>
                    </Row>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete: (data: ActionCompletePayload) => void; // Callback when setup is complete
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useCallback((payload: ActionCompletePayload) => { props.onComplete(payload); }, [props]);

  // State for multi-step wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || (props.roleOptions[0] || ''),
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  // Email regex for validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  // Validate email format
  const validateEmail = useCallback((email: string): boolean => {
    return emailRegex.test(email);
  }, []);

  // Validate step 1 fields
  const validateStep1 = useCallback((): boolean => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData.name, formData.email, validateEmail]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  }, [currentStep, validateStep1]);

  // Handle back button
  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
  }, [currentStep]);

  // Handle complete setup
  const handleComplete = useCallback(() => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [formData, complete]);

  // Update form data
  const updateFormData = useCallback((field: string, value: any) => {
    setFormData((prev) => ({
      ...prev,
      [field]: value,
    }));
    // Clear error when user starts typing
    if (errors[field as keyof typeof errors]) {
      setErrors((prev) => ({
        ...prev,
        [field]: undefined,
      }));
    }
  }, [errors]);

  return { complete, currentStep, setCurrentStep, formData, updateFormData, handleNext, handleBack, handleComplete, errors };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const { currentStep, formData, updateFormData, handleNext, handleBack, handleComplete, errors } = state;
  const totalSteps = 3;
  const progress = (currentStep / totalSteps) * 100;

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={32}>
        {/* Step Indicator */}
        <Stack gap={16}>
          <Stack direction="horizontal" align="center" justify="between" gap={8}>
            <Stack gap={4}>
              <Heading level={2} style={{ margin: 0 }}>Setup Your Profile</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {currentStep} of {totalSteps}
              </Text>
            </Stack>
            <Badge variant="primary" size="md">
              {currentStep}/{totalSteps}
            </Badge>
          </Stack>
          {/* Progress Bar */}
          <Progress value={progress} max={100} variant="default" size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={20}>
              <Heading level={3}>Profile Information</Heading>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={(value) => updateFormData('name', value)}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => updateFormData('email', value)}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap={12}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Choose Avatar
                </Text>
                 <Stack direction="horizontal" gap={12} align="center" wrap>
                  {props.avatarOptions.map((avatarEmoji) => (
                    <Box
                      key={avatarEmoji}
                      as={Clickable}
                      onClick={() => updateFormData('avatar', avatarEmoji)}
                      style={{
                        padding: 'var(--ggui-spacing-2, 8px)',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        border: formData.avatar === avatarEmoji
                          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                          : '2px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                    >
                      <Text size="2xl">{avatarEmoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={20}>
              <Heading level={3}>Preferences</Heading>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => updateFormData('role', value)}
                options={props.roleOptions.map((role) => ({
                  value: role,
                  label: role,
                }))}
              />

              {/* Email Notifications Toggle */}
              <Stack gap={8}>
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => updateFormData('emailNotifications', checked)}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Receive email updates about your account and new features
                </Text>
              </Stack>

              {/* Theme Preference Toggle */}
              <Stack gap={8}>
                <Stack direction="horizontal" align="center" gap={12}>
                  <Icon name="sun" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                  <Toggle
                    label="Dark Theme"
                    checked={formData.theme === 'dark'}
                    onChange={(checked) => updateFormData('theme', checked ? 'dark' : 'light')}
                    size="md"
                  />
                  <Icon name="moon" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                </Stack>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Choose your preferred color scheme
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={20}>
              <Heading level={3}>Review Your Setup</Heading>

              {/* Profile Summary */}
              <Box
                paddingX={16}
                paddingY={12}
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Stack gap={12}>
                  <Stack direction="horizontal" align="center" gap={12}>
                    <Text size="2xl">{formData.avatar}</Text>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{formData.name}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Box>

              <Divider margin={12} />

              {/* Preferences Summary */}
              <Stack gap={12}>
                 <Stack direction="horizontal" gap={32} align="start" wrap>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{formData.role}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                    <Badge variant={formData.emailNotifications ? 'success' : 'default'} size="sm">
                      {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                    <Badge variant="primary" size="sm">
                      {formData.theme === 'dark' ? 'Dark' : 'Light'}
                    </Badge>
                  </Stack>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
         <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>

          <Spacer size="flex" />

          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={state.currentStep === 1 ? () => {
                const isValid = !errors.name && !errors.email && formData.name.trim() && formData.email.trim();
                if (isValid) {
                  handleNext();
                } else {
                  const newErrors: { name?: string; email?: string } = {};
                  if (!formData.name.trim()) newErrors.name = 'Name is required';
                  if (!formData.email.trim()) newErrors.email = 'Email is required';
                  else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) newErrors.email = 'Please enter a valid email address';
                  setErrors(newErrors);
                }
              } : handleNext}
            >
              Next
            </Button>
          )}

          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
